}

impl ConnectApi for Api<'_> {
    type Part = Part;

    fn part_attrs(&self, part: Part) -> AttrMap {
        match part {
            Part::Root => self.root_attrs(),
            Part::Frame => self.frame_attrs(),
            Part::Pattern => self.pattern_attrs(),
            Part::Overlay => self.overlay_attrs(),
